import React, { useState } from 'react';
import {
  Box,
  Paper,
  TextField,
  Button,
  Typography,
  Alert,
  CircularProgress,
  Divider,
  Container,
  Tab,
  Tabs,
} from '@mui/material';
import fetchModel from '../../lib/fetchModelData';
import './styles.css';

function LoginRegister({ onLoginSuccess }) {
  // State quản lý tab (Login / Register)
  const [tabValue, setTabValue] = useState(0);

  // State cho form Đăng ký — bao gồm đầy đủ các trường theo yêu cầu
  const [registerForm, setRegisterForm] = useState({
    login_name: '',
    password: '',
    confirm_password: '',
    first_name: '',
    last_name: '',
    location: '',
    description: '',
    occupation: '',
  });

  // State cho form Đăng nhập
  const [loginForm, setLoginForm] = useState({
    login_name: '',
    password: '',
  });

  // State cho thông báo lỗi/thành công
  const [registerMessage, setRegisterMessage] = useState({
    type: '', // 'success', 'error'
    text: '',
  });

  const [loginMessage, setLoginMessage] = useState({
    type: '',
    text: '',
  });

  // State cho loading
  const [isRegisterLoading, setIsRegisterLoading] = useState(false);
  const [isLoginLoading, setIsLoginLoading] = useState(false);

  // ===== ĐĂNG KÝ =====
  const handleRegisterChange = (e) => {
    const { name, value } = e.target;
    setRegisterForm((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  // Kiểm tra mật khẩu có khớp không (dùng cho disable nút)
  const isPasswordMismatch =
    registerForm.password !== '' &&
    registerForm.confirm_password !== '' &&
    registerForm.password !== registerForm.confirm_password;

  const handleRegisterSubmit = async (e) => {
    e.preventDefault();
    setRegisterMessage({ type: '', text: '' });

    // Validate nghiêm ngặt: login_name, password, first_name, last_name bắt buộc
    if (!registerForm.login_name.trim()) {
      setRegisterMessage({ type: 'error', text: 'Tên đăng nhập là bắt buộc' });
      return;
    }
    if (!registerForm.first_name.trim()) {
      setRegisterMessage({ type: 'error', text: 'Tên là bắt buộc' });
      return;
    }
    if (!registerForm.last_name.trim()) {
      setRegisterMessage({ type: 'error', text: 'Họ là bắt buộc' });
      return;
    }
    if (!registerForm.password.trim()) {
      setRegisterMessage({ type: 'error', text: 'Mật khẩu là bắt buộc' });
      return;
    }
    if (!registerForm.confirm_password.trim()) {
      setRegisterMessage({ type: 'error', text: 'Vui lòng xác nhận mật khẩu' });
      return;
    }

    // Kiểm tra mật khẩu khớp
    if (registerForm.password !== registerForm.confirm_password) {
      setRegisterMessage({
        type: 'error',
        text: 'Mật khẩu xác nhận không khớp!',
      });
      return;
    }

    setIsRegisterLoading(true);

    try {
      // Gọi API đăng ký — gửi đầy đủ thông tin
      const response = await fetchModel('/user', 'POST', {
        login_name: registerForm.login_name,
        password: registerForm.password,
        first_name: registerForm.first_name,
        last_name: registerForm.last_name,
        location: registerForm.location,
        description: registerForm.description,
        occupation: registerForm.occupation,
      });

      // Thành công — xóa form + hiển thị thông báo
      setRegisterMessage({
        type: 'success',
        text: '✅ Đăng ký thành công! Vui lòng đăng nhập.',
      });

      // Xóa trống tất cả ô input
      setRegisterForm({
        login_name: '',
        password: '',
        confirm_password: '',
        first_name: '',
        last_name: '',
        location: '',
        description: '',
        occupation: '',
      });

      // Chuyển sang tab Đăng nhập sau 2 giây
      setTimeout(() => {
        setTabValue(0);
      }, 2000);
    } catch (err) {
      // Lỗi — hiển thị lỗi cụ thể từ backend
      setRegisterMessage({
        type: 'error',
        text: `❌ ${err.message || 'Đăng ký thất bại'}`,
      });
    } finally {
      setIsRegisterLoading(false);
    }
  };

  // ===== ĐĂNG NHẬP =====
  const handleLoginChange = (e) => {
    const { name, value } = e.target;
    setLoginForm((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleLoginSubmit = async (e) => {
    e.preventDefault();
    setLoginMessage({ type: '', text: '' });

    if (!loginForm.login_name.trim() || !loginForm.password.trim()) {
      setLoginMessage({
        type: 'error',
        text: 'Vui lòng nhập đầy đủ tên đăng nhập và mật khẩu',
      });
      return;
    }

    setIsLoginLoading(true);

    try {
      // Gọi API đăng nhập — gửi cả login_name VÀ password
      const response = await fetchModel('/admin/login', 'POST', {
        login_name: loginForm.login_name,
        password: loginForm.password,
      });

      // Đăng nhập thành công - gọi callback với dữ liệu từ server
      if (onLoginSuccess) {
        onLoginSuccess(response.data);
      }
    } catch (err) {
      // Đăng nhập thất bại - hiển thị lỗi từ backend
      setLoginMessage({
        type: 'error',
        text: `❌ ${err.message || 'Đăng nhập thất bại'}`,
      });
    } finally {
      setIsLoginLoading(false);
    }
  };

  return (
    <Container maxWidth="sm" className="login-register-container">
      <Paper elevation={3} sx={{ p: 4, mt: 4 }}>
        <Typography variant="h4" textAlign="center" gutterBottom sx={{ fontWeight: 'bold', mb: 3 }}>
          📸 Photo Sharing
        </Typography>

        {/* Tabs */}
        <Tabs
          value={tabValue}
          onChange={(e, newValue) => setTabValue(newValue)}
          variant="fullWidth"
          sx={{ mb: 3 }}
        >
          <Tab label="🔐 Đăng Nhập" />
          <Tab label="✍️ Đăng Ký" />
        </Tabs>

        {/* ===== TAB ĐĂNG NHẬP ===== */}
        {tabValue === 0 && (
          <Box component="form" onSubmit={handleLoginSubmit}>
            <Typography variant="h6" sx={{ mb: 2 }}>
              Đăng nhập tài khoản
            </Typography>

            {loginMessage.text && (
              <Alert severity={loginMessage.type} sx={{ mb: 2 }}>
                {loginMessage.text}
              </Alert>
            )}

            <TextField
              fullWidth
              label="Tên đăng nhập"
              name="login_name"
              type="text"
              value={loginForm.login_name}
              onChange={handleLoginChange}
              margin="normal"
              placeholder="Nhập tên đăng nhập của bạn"
              disabled={isLoginLoading}
            />

            <TextField
              fullWidth
              label="Mật khẩu"
              name="password"
              type="password"
              value={loginForm.password}
              onChange={handleLoginChange}
              margin="normal"
              placeholder="Nhập mật khẩu"
              disabled={isLoginLoading}
            />

            <Button
              fullWidth
              variant="contained"
              color="primary"
              type="submit"
              sx={{ mt: 3 }}
              disabled={isLoginLoading}
            >
              {isLoginLoading ? <CircularProgress size={24} /> : 'Đăng Nhập'}
            </Button>

            <Typography variant="body2" textAlign="center" sx={{ mt: 2, color: 'text.secondary' }}>
              Chưa có tài khoản? <span style={{ cursor: 'pointer', color: '#1976d2' }} onClick={() => setTabValue(1)}>Đăng ký</span>
            </Typography>
          </Box>
        )}

        {/* ===== TAB ĐĂNG KÝ ===== */}
        {tabValue === 1 && (
          <Box component="form" onSubmit={handleRegisterSubmit}>
            <Typography variant="h6" sx={{ mb: 2 }}>
              Tạo tài khoản mới
            </Typography>

            {registerMessage.text && (
              <Alert severity={registerMessage.type} sx={{ mb: 2 }}>
                {registerMessage.text}
              </Alert>
            )}

            <TextField
              fullWidth
              label="Tên đăng nhập *"
              name="login_name"
              type="text"
              value={registerForm.login_name}
              onChange={handleRegisterChange}
              margin="normal"
              placeholder="Chọn tên đăng nhập"
              disabled={isRegisterLoading}
              required
            />

            <TextField
              fullWidth
              label="Mật khẩu *"
              name="password"
              type="password"
              value={registerForm.password}
              onChange={handleRegisterChange}
              margin="normal"
              placeholder="Nhập mật khẩu"
              disabled={isRegisterLoading}
              required
            />

            <TextField
              fullWidth
              label="Xác nhận mật khẩu *"
              name="confirm_password"
              type="password"
              value={registerForm.confirm_password}
              onChange={handleRegisterChange}
              margin="normal"
              placeholder="Nhập lại mật khẩu"
              disabled={isRegisterLoading}
              required
              error={isPasswordMismatch}
              helperText={isPasswordMismatch ? 'Mật khẩu không khớp!' : ''}
            />

            <Divider sx={{ my: 2 }}>Thông tin cá nhân</Divider>

            <TextField
              fullWidth
              label="Tên *"
              name="first_name"
              type="text"
              value={registerForm.first_name}
              onChange={handleRegisterChange}
              margin="normal"
              placeholder="Tên của bạn"
              disabled={isRegisterLoading}
              required
            />

            <TextField
              fullWidth
              label="Họ *"
              name="last_name"
              type="text"
              value={registerForm.last_name}
              onChange={handleRegisterChange}
              margin="normal"
              placeholder="Họ của bạn"
              disabled={isRegisterLoading}
              required
            />

            <TextField
              fullWidth
              label="Vị trí"
              name="location"
              type="text"
              value={registerForm.location}
              onChange={handleRegisterChange}
              margin="normal"
              placeholder="Ví dụ: Hà Nội, Việt Nam"
              disabled={isRegisterLoading}
            />

            <TextField
              fullWidth
              label="Mô tả bản thân"
              name="description"
              type="text"
              value={registerForm.description}
              onChange={handleRegisterChange}
              margin="normal"
              placeholder="Giới thiệu ngắn về bạn"
              disabled={isRegisterLoading}
              multiline
              maxRows={3}
            />

            <TextField
              fullWidth
              label="Nghề nghiệp"
              name="occupation"
              type="text"
              value={registerForm.occupation}
              onChange={handleRegisterChange}
              margin="normal"
              placeholder="Ví dụ: Sinh viên, Kỹ sư"
              disabled={isRegisterLoading}
            />

            <Button
              fullWidth
              variant="contained"
              color="success"
              type="submit"
              sx={{ mt: 3 }}
              disabled={isRegisterLoading || isPasswordMismatch}
            >
              {isRegisterLoading ? <CircularProgress size={24} /> : 'Register Me'}
            </Button>

            <Typography variant="body2" textAlign="center" sx={{ mt: 2, color: 'text.secondary' }}>
              Đã có tài khoản? <span style={{ cursor: 'pointer', color: '#1976d2' }} onClick={() => setTabValue(0)}>Đăng nhập</span>
            </Typography>
          </Box>
        )}
      </Paper>
    </Container>
  );
}

export default LoginRegister;
